import{_ as a,o,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Profile (New)","description":"","frontmatter":{"title":"Profile (New)","slug":"profile-new"},"headers":[],"relativePath":"account-hub/profile-new.md","filePath":"account-hub/profile-new.md"}'),n={name:"account-hub/profile-new.md"};function l(i,e,s,h,p,u){return o(),t("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Use the <strong>Profile</strong> tab on the <strong>Manage account</strong> page to manage your Branch account. This includes your name, role, preferences, and more. You can also view your user ID and account email.</p><div class="info custom-block"><p class="custom-block-title">Your title goes here</p><p>Your content goes here</p></div><h2 id="open-the-profile-tab" tabindex="-1">Open the Profile tab <a class="header-anchor" href="#open-the-profile-tab" aria-label="Permalink to &quot;Open the Profile tab&quot;">​</a></h2><p>Follow these steps to open the <strong>Profile</strong> tab:</p><ol><li>In Branch, select the app/profile drop-down menu in the top-left corner of the page.</li><li>Select <strong>Manage account</strong> below your name in the drop-down menu.</li></ol><h2 id="update-profile" tabindex="-1">Update profile <a class="header-anchor" href="#update-profile" aria-label="Permalink to &quot;Update profile&quot;">​</a></h2><p>On the <strong>Profile</strong> tab in the <strong>Manage account</strong> section in Branch, you can update your name, avatar, and user ID.</p><h3 id="update-your-name" tabindex="-1">Update your name <a class="header-anchor" href="#update-your-name" aria-label="Permalink to &quot;Update your name&quot;">​</a></h3><p>Your name is the name that will appear in Branch and the name that automated emails from Branch will be addressed to.</p><p>Follow these steps to update your Branch account name:</p><ol><li>On the <strong>Profile</strong> tab, edit your name in the <strong>Your name</strong> text box.</li><li>Select <strong>Save changes</strong>.</li></ol><h3 id="update-your-avatar" tabindex="-1">Update your avatar <a class="header-anchor" href="#update-your-avatar" aria-label="Permalink to &quot;Update your avatar&quot;">​</a></h3><p>Your avatar is how you&#39;ll appear in Branch.</p><p>Follow these steps to update your Branch avatar:</p><ol><li>On the <strong>Profile</strong> tab, select the <strong>Choose File</strong> button.</li><li>Choose the file you want to upload.</li><li>Select <strong>Save changes</strong>.</li></ol><h3 id="personalization" tabindex="-1">Personalization <a class="header-anchor" href="#personalization" aria-label="Permalink to &quot;Personalization&quot;">​</a></h3><p>You can set your role, industry, and primary goal on the <strong>Profile</strong> tab. Setting these helps Branch personalize your experience.</p><h2 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h2><p>To learn more about the <strong>Billing</strong> tab, check out our <a href="https://help.branch.io/docs/billing-new" target="_blank" rel="noreferrer">Billing</a> section.</p>',20)])])}const g=a(n,[["render",l]]);export{d as __pageData,g as default};
